import React, { useEffect, useState } from "react";
import { FaHome, FaUser, FaCog, FaBars, FaTimes } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import "./dashboardhome.css";

const DashboardHome = () => {
  const [isOpen, setIsOpen] = useState(true);
  const navigate = useNavigate();

  // Vérifier le rôle de l'utilisateur
  useEffect(() => {
    const userRole = localStorage.getItem("userRole");
    if (userRole !== "admin") {
      navigate("/login"); // Redirige si l'utilisateur n'est pas un admin
    }
  }, [navigate]);

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <div className={`sidebar ${isOpen ? "open" : "closed"}`}>
        <button className="toggle-btn" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <FaTimes /> : <FaBars />}
        </button>
        <ul>
          <li>
            <FaHome /> {isOpen && <span>Home</span>}
          </li>
          <li>
            <FaUser /> {isOpen && <span>Profile</span>}
          </li>
          <li>
            <FaCog /> {isOpen && <span>Settings</span>}
          </li>
        </ul>
      </div>

      {/* Contenu principal */}
      <div className="dashboard-content">
        <h1>Dashboard Admin</h1>
        <p>Bienvenue sur votre tableau de bord administrateur.</p>
      </div>
    </div>
  );
};

export default DashboardHome;
